package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  private static class JsonArraySubclass extends JsonArray {
    @Override
    public JsonElement deepCopy() {
      return null;
    }
  }

  private static class JsonElementSubclass extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return null;
    }
  }

  @Test
  void testIsJsonArray_whenInstanceIsJsonArray_returnsTrue() {
    JsonElement element = new JsonArraySubclass();
    assertTrue(element.isJsonArray());
  }

  @Test
  void testIsJsonArray_whenInstanceIsNotJsonArray_returnsFalse() {
    JsonElement element = new JsonElementSubclass();
    assertFalse(element.isJsonArray());
  }
}
